{
  description = "personal-kanban — a personal kanban board CLI and TUI";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    rust-overlay.url = "github:oxalica/rust-overlay";
    flake-utils.url = "github:numtide/flake-utils";
    crane.url = "github:ipetkov/crane";
    crane.inputs.nixpkgs.follows = "nixpkgs";
    crane.inputs.rust-overlay.follows = "rust-overlay";
  };

  outputs = {
    self,
    nixpkgs,
    rust-overlay,
    flake-utils,
    crane,
    ...
  }:
    flake-utils.lib.eachDefaultSystem (system: let
      overlays = [(import rust-overlay)];
      pkgs = import nixpkgs {
        inherit system overlays;
      };
      craneLib = (crane.mkLib pkgs).overrideToolchain (
        pkgs.rust-bin.stable.latest.default.override {
          extensions = ["rust-src" "clippy" "rustfmt"];
        }
      );

      # Common sources
      src = craneLib.cleanCargoSource ./.;

      # Darwin-specific build inputs
      darwinBuildInputs = with pkgs;
        lib.optionals stdenv.isDarwin [
          libiconv
          darwin.apple_sdk.frameworks.Security
        ];

      # Cargo.toml attributes for crane
      cargoArtifacts = craneLib.buildDepsOnly {
        inherit src;
        nativeBuildInputs = [pkgs.pkg-config];
        buildInputs = darwinBuildInputs;
      };

      kanbanPackage = craneLib.buildPackage {
        inherit src cargoArtifacts;
        nativeBuildInputs = [pkgs.pkg-config];
        buildInputs = darwinBuildInputs;

        # Create the pk symlink in postInstall
        postInstall = ''
          ln -s $out/bin/kanban $out/bin/pk
        '';

        meta = {
          description = "A personal kanban board CLI and TUI";
          license = pkgs.lib.licenses.mit;
          mainProgram = "kanban";
        };
      };
    in {
      packages.default = kanbanPackage;

      devShells.default = pkgs.mkShell {
        buildInputs = [
          pkgs.rust-bin.stable.latest.default.override {
            extensions = ["rust-src" "clippy" "rustfmt" "rust-analyzer"];
          }
          pkgs.cargo-watch
          pkgs.pkg-config
          pkgs.sqlite
          pkgs.just
          pkgs.alejandra
          pkgs.statix
          pkgs.cargo-tarpaulin
        ] ++ darwinBuildInputs;
      };

      formatter = pkgs.alejandra;
    });
}

